```python
def add(x, y):
    return x + y

def subtract(x, y):
    return x - y

def multiply(x, y):
    return x * y

def divide(x, y):
    if y == 0:
        return "Kan inte dela med noll!"
    return x / y

def calculator():
    print("Välj en operation:")
    print("1. Addition")
    print("2. Subtraktion")
    print("3. Multiplikation")
    print("4. Division")

    choice = input("Skriv valet (1/2/3/4): ")

    if choice in ['1', '2', '3', '4']:
        num1 = float(input("Ange första numret: "))
        num2 = float(input("Ange andra numret: "))

        if choice == '1':
            print(f"{num1} + {num2} = {add(num1, num2)}")
        elif choice == '2':
            print(f"{num1} - {num2} = {subtract(num1, num2)}")
        elif choice == '3':
            print(f"{num1} * {num2} = {multiply(num1, num2)}")
        elif choice == '4':
            print(f"{num1} / {num2} = {divide(num1, num2)}")
    else:
        print("Ogiltigt val!")

if __name__ == "__main__":
    calculator()
